// ── Sentiment Analyser ───────────────────────────────────────
const rawTickets   = $node['📥 Fetch Resolved Tickets'].json;
const rawUsability = $node['📥 Fetch Usability Results'].json;

const tickets   = Array.isArray(rawTickets)   ? rawTickets   : (rawTickets.data   || []);
const usability = Array.isArray(rawUsability) ? rawUsability : (rawUsability.data || []);

const sentimentItems = [];

// Analyse support tickets — resolved quickly = positive, escalated = negative
tickets.forEach(t => {
  sentimentItems.push({
    source:         'support_ticket',
    vertical:       t.vertical,
    sentiment:      'positive',
    score:          0.6,
    feedback_text:  `${t.issue_type} resolved successfully`,
    category:       t.issue_type?.toLowerCase().replace(/ /g,'_'),
    sprint:         4
  });
});

// Analyse usability results
usability.forEach(u => {
  const sentiment = u.success && u.difficulty_rating <= 2 ? 'positive' :
                    u.success && u.difficulty_rating <= 3 ? 'neutral'  : 'negative';
  const score     = u.success ? (u.difficulty_rating <= 2 ? 0.8 : 0.3) : -0.6;
  sentimentItems.push({
    source:         'usability_test',
    vertical:       null,
    sentiment,
    score,
    feedback_text:  `${u.persona} task: "${u.task}" — ${u.success ? 'succeeded' : 'failed'} (difficulty: ${u.difficulty_rating}/5)`,
    category:       u.task?.toLowerCase().substring(0, 30),
    sprint:         4
  });
});

const positive = sentimentItems.filter(s => s.sentiment === 'positive').length;
const negative = sentimentItems.filter(s => s.sentiment === 'negative').length;
const total    = sentimentItems.length;
const avgScore = total > 0 ? (sentimentItems.reduce((s, i) => s + i.score, 0) / total).toFixed(2) : 0;

return [{ json: { sentimentItems, summary: { total, positive, negative, neutral: total - positive - negative, avgScore } } }];
